import { useMemo, useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { addVehicle } from "../../api/vehicleApi";

export default function AddVehicle() {
  const navigate = useNavigate();

  const [vehicle, setVehicle] = useState({
    brand: "",
    type: "",
    year: "",
    price: "",
    status: "available",
    vehicleNumber: "",
    details: "",
  });

  const [images, setImages] = useState([]); // File[]
  const previews = useMemo(() => images.map((f) => URL.createObjectURL(f)), [images]);

  useEffect(() => {
    return () => previews.forEach((u) => URL.revokeObjectURL(u));
  }, [previews]);

  const [saving, setSaving] = useState(false);

  const vehicleTypes = ["SUV", "Sedan", "Hatchback", "Truck", "Van", "Coupe"];
  const statuses = ["available", "reserved", "sold"];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setVehicle((prev) => ({ ...prev, [name]: value }));
  };

  const onPickImages = (e) => {
    const files = Array.from(e.target.files || []).slice(0, 4);
    setImages(files);
    e.target.value = "";
  };

  const removeImage = (idx) => {
    setImages((prev) => prev.filter((_, i) => i !== idx));
  };

  const submit = async (e) => {
    e.preventDefault();

    const currentYear = new Date().getFullYear();
    const yearNum = Number(vehicle.year);
    const priceNum = Number(vehicle.price);

    if (!vehicle.brand.trim()) return alert("Brand is required");
    if (!vehicle.type) return alert("Vehicle type is required");
    if (!vehicle.year) return alert("Year is required");
    if (Number.isNaN(yearNum)) return alert("Year must be a number");
    if (yearNum > currentYear) return alert(`Year cannot be in the future (max ${currentYear})`);
    if (yearNum < 1900) return alert("Year must be >= 1900");

    if (!vehicle.price) return alert("Price is required");
    if (Number.isNaN(priceNum) || priceNum < 0) return alert("Price must be >= 0");

    const fd = new FormData();
    fd.append("brand", vehicle.brand.trim());
    fd.append("type", vehicle.type);
    fd.append("year", String(yearNum));
    fd.append("price", String(priceNum));
    fd.append("status", vehicle.status);
    fd.append("vehicleNumber", vehicle.vehicleNumber.trim());
    fd.append("details", vehicle.details.trim());

    images.forEach((file) => fd.append("images", file));

    try {
      setSaving(true);
      await addVehicle(fd);
      alert("Vehicle added successfully");
      navigate("/vehicles");
    } catch (err) {
      alert(err.response?.data?.message || "Error adding vehicle");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Add Vehicle</div>
          <div className="pageSub">Add a new vehicle to inventory</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 860, margin: "32px auto" }}>
        <form onSubmit={submit}>
          <label className="label">Brand</label>
          <input
            className="input"
            name="brand"
            placeholder="Vehicle Brand"
            value={vehicle.brand}
            onChange={handleChange}
            required
          />

          <label className="label">Type</label>
          <select
            className="select"
            name="type"
            value={vehicle.type}
            onChange={handleChange}
            required
            style={{ marginBottom: 16 }}
          >
            <option value="">Select Type</option>
            {vehicleTypes.map((t) => <option key={t} value={t}>{t}</option>)}
          </select>

          <label className="label">Year</label>
          <input
            className="input"
            name="year"
            type="number"
            placeholder="Year"
            value={vehicle.year}
            onChange={handleChange}
            required
          />

          <label className="label">Price</label>
          <input
            className="input"
            name="price"
            type="number"
            placeholder="Price"
            value={vehicle.price}
            onChange={handleChange}
            required
          />

          <label className="label">Status</label>
          <select
            className="select"
            name="status"
            value={vehicle.status}
            onChange={handleChange}
            style={{ marginBottom: 16 }}
          >
            {statuses.map((s) => <option key={s} value={s}>{s}</option>)}
          </select>

          <label className="label">Vehicle Number</label>
          <input
            className="input"
            name="vehicleNumber"
            placeholder="Vehicle Number/Registration"
            value={vehicle.vehicleNumber}
            onChange={handleChange}
          />

          <label className="label">Details</label>
          <textarea
            className="textarea"
            name="details"
            rows={3}
            placeholder="Additional vehicle details"
            value={vehicle.details}
            onChange={handleChange}
          />

          <label className="label">Photos (max 4)</label>
          <input
            type="file"
            accept="image/*"
            multiple
            onChange={onPickImages}
            style={{ marginBottom: 16 }}
          />

          {previews.length > 0 && (
            <div style={{ display: "flex", gap: 12, flexWrap: "wrap", marginBottom: 20 }}>
              {previews.map((src, idx) => (
                <div key={src} style={{ border: "1px solid var(--border)", padding: 8, borderRadius: "var(--radius)" }}>
                  <div style={{ width: 220, aspectRatio: "4 / 3", overflow: "hidden", borderRadius: 8 }}>
                    <img src={src} alt="preview" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                  </div>
                  <button
                    type="button"
                    onClick={() => removeImage(idx)}
                    className="btn"
                    style={{ marginTop: 8, width: "100%" }}
                  >
                    Remove
                  </button>
                </div>
              ))}
            </div>
          )}

          <button type="submit" className="btn btnPrimary" style={{ width: "100%", marginTop: 8 }} disabled={saving}>
            {saving ? "Saving..." : "Save Vehicle"}
          </button>
        </form>
      </div>
    </div>
  );
}
